fn app_stack_region(args: &[String], envs: &[String], auxv: &[AuxEntry], sp: usize) -> Vec<u8> {
    let mut data = VecDeque::new();
    let mut push = |src: &[u8]| -> usize {
        data.extend(src.iter().cloned());
        data.rotate_right(src.len());
        sp - data.len()
    };

    let random_str_pos = push(b"0123456789abcdef");
    let envs_slice: Vec<_> = envs
        .iter()
        .map(|env| {
            push(b"\0");
            push(env.as_bytes())
        })
        .collect();
    let argv_slice: Vec<_> = args
        .iter()
        .map(|arg| {
            push(b"\0");
            push(arg.as_bytes())
        })
        .collect();

    let padding_null = [0u8; core::mem::size_of::<usize>()];
    let sp = push(&padding_null);
    push(&vec![0; sp % 16]);

    if (envs.len() + args.len() + 3) & 1 != 0 {
        push(&padding_null);
    }

    push(AuxEntry::new(AuxType::NULL, 0).as_bytes());

    let mut has_random = false;
    let mut has_execfn = false;
    for entry in auxv {
        has_random |= entry.get_type() == AuxType::RANDOM;
        has_execfn |= entry.get_type() == AuxType::EXECFN;
    }
    push(auxv.as_bytes());
    if !has_random {
        push(AuxEntry::new(AuxType::RANDOM, random_str_pos).as_bytes());
    }
    if !has_execfn {
        let execfn = argv_slice.first().copied().unwrap_or(0);
        push(AuxEntry::new(AuxType::EXECFN, execfn).as_bytes());
    }

    push(&padding_null);
    push(envs_slice.as_bytes());
    push(&padding_null);
    push(argv_slice.as_bytes());
    let sp = push(args.len().as_bytes());

    assert!(sp % 16 == 0);

    let mut result = Vec::with_capacity(data.len());
    let (first, second) = data.as_slices();
    result.extend_from_slice(first);
    result.extend_from_slice(second);
    result
}

