const DIR_PERMISSION: NodePermission = NodePermission::from_bits_truncate(0o755);

fn mount_at(fs: &FsContext, path: &str, mount_fs: Filesystem) -> LinuxResult<()> {
    if fs.resolve(path).is_err() {
        fs.create_dir(path, DIR_PERMISSION)?;
    }
    fs.resolve(path)?.mount(&mount_fs)?;
    info!("Mounted {} at {}", mount_fs.name(), path);
    Ok(())
}

/// Mount all filesystems
pub fn mount_all() -> LinuxResult<()> {
    info!("Initialize pseudofs...");

    let fs = FS_CONTEXT.lock();
    mount_at(&fs, "/dev", dev::new_devfs())?;
    mount_at(&fs, "/dev/shm", tmp::MemoryFs::new())?;
    mount_at(&fs, "/tmp", tmp::MemoryFs::new())?;
    mount_at(&fs, "/proc", proc::new_procfs())?;

    mount_at(&fs, "/sys", tmp::MemoryFs::new())?;
    let mut path = PathBuf::new();
    for comp in Path::new("/sys/class/graphics/fb0/device").components() {
        path.push(comp.as_str());
        if fs.resolve(&path).is_err() {
            fs.create_dir(&path, DIR_PERMISSION)?;
        }
    }
    path.push("subsystem");
    fs.symlink("whatever", &path, (0, 0))?;

    // Mount extra block devices (e.g. test disk) to /sdcard
    if let Some(mut extra_devs) = axfs::take_extra_block_devs() {
        if let Some(dev) = extra_devs.take_one() {
            info!("  mounting extra block device: {:?}", dev.device_name());
            match axfs::new_default(dev) {
                Ok(disk_fs) => {
                    mount_at(&fs, "/sdcard", disk_fs)?;
                    for (alias, target) in [("/glibc", "/sdcard/glibc"), ("/musl", "/sdcard/musl")]
                    {
                        if fs.resolve(alias).is_err() {
                            fs.symlink(target, alias, (0, 0))?;
                        }
                    }
                }
                Err(e) => {
                    warn!("  failed to mount extra block device: {:?}", e);
                }
            }
        }
    }

    drop(fs);

    #[cfg(feature = "dev-log")]
    dev::bind_dev_log().expect("Failed to bind /dev/log");

    Ok(())
}

