fn fd_is_path(fd: i32) -> bool {
    FD_TABLE
        .read()
        .get(fd as usize)
        .is_some_and(|fd| fd.status_flags() & O_PATH as c_int != 0)
}

fn proc_fd_path_fd(path: &str) -> Option<i32> {
    if let Some(fd) = path.strip_prefix("/proc/self/fd/") {
        return fd.parse().ok();
    }

    let rest = path.strip_prefix("/proc/")?;
    let (pid, rest) = rest.split_once('/')?;
    if rest.strip_prefix("fd/").is_some()
        && pid.parse::<u32>().ok()? == current().as_thread().proc_data.proc.pid()
    {
        rest.strip_prefix("fd/")?.parse().ok()
    } else {
        None
    }
}

fn targets_path_fd(dirfd: i32, path: Option<&str>, flags: u32) -> bool {
    let empty_at_fd = path.is_none_or(str::is_empty) && flags & AT_EMPTY_PATH != 0;
    (empty_at_fd && fd_is_path(dirfd)) || path.and_then(proc_fd_path_fd).is_some_and(fd_is_path)
}

/// The ioctl() system call manipulates the underlying device parameters
/// of special files.
pub fn sys_ioctl(fd: i32, cmd: u32, arg: usize) -> AxResult<isize> {
    debug!("sys_ioctl <= fd: {fd}, cmd: {cmd}, arg: {arg}");
    let f = get_file_like(fd)?;
    if cmd == FIONBIO {
        let val = (arg as *const u8).vm_read()?;
        if val != 0 && val != 1 {
            return Err(AxError::InvalidInput);
        }
        f.set_nonblocking(val != 0)?;
        return Ok(0);
    }
    f.ioctl(cmd, arg)
        .map(|result| result as isize)
        .inspect_err(|err| {
            if *err == AxError::NotATty {
                // glibc likes to call TIOCGWINSZ on non-terminal files, just
                // ignore it
                if cmd == TIOCGWINSZ {
                    return;
                }
                warn!("Unsupported ioctl command: {cmd} for fd: {fd}");
            }
        })
}

pub fn sys_chdir(path: *const c_char) -> AxResult<isize> {
    let path = vm_load_string(path)?;
    debug!("sys_chdir <= path: {path}");

    let mut fs = FS_CONTEXT.lock();
    let entry = fs.resolve(&path).inspect_err(|err| {
        warn!("sys_chdir failed to resolve path {path:?}: {err:?}");
    })?;
    fs.set_current_dir(entry).inspect_err(|err| {
        warn!("sys_chdir failed to set cwd to {path:?}: {err:?}");
    })?;
    Ok(0)

