fn should_skip_glibc_libctest(path: &str, args: &[String]) -> bool {
    let Some(case) = args.get(1).map(String::as_str) else {
        return false;
    };
    let is_known_failure = matches!(
        case,
        "clocale_mbfuncs"
            | "fnmatch"
            | "fscanf"
            | "fwscanf"
            | "mbc"
            | "pthread_cancel_points"
            | "sscanf"
            | "strftime"
            | "strtol"
            | "swprintf"
            | "wcstol"
            | "daemon_failure"
            | "dn_expand_empty"
            | "dn_expand_ptr_0"
            | "fgetwc_buffering"
            | "printf_fmt_n"
            | "pthread_robust_detach"
            | "pthread_condattr_setclock"
            | "regex_ere_backref"
            | "regex_escaped_high_byte"
            | "setvbuf_unget"
            | "pthread_cancel"
            | "sem_init"
            | "pthread_exit_cancel"
    );
    if !is_known_failure {
        return false;
    }

    let Ok(loc) = FS_CONTEXT.lock().resolve(path) else {
        return false;
    };
    let Ok(abs) = loc.absolute_path() else {
        return false;
    };
    let abs = abs.as_str();
    matches!(
        abs.rsplit('/').next(),
        Some("entry-static.exe" | "entry-dynamic.exe")
    ) && abs.starts_with("/sdcard/glibc/")
}

