    updatable: bool,
}

/// Global key store and per-process keyrings.
pub struct KeyringManager {
    /// All keys indexed by serial number.
    keys: BTreeMap<i32, Arc<Mutex<Key>>>,
    /// Per-process keyring: task_id → (keyring key ids).
    process_keyrings: BTreeMap<u64, Vec<i32>>,
    /// Next serial number.
    next_serial: i32,
}

impl KeyringManager {
    pub const fn new() -> Self {
        Self {
            keys: BTreeMap::new(),
            process_keyrings: BTreeMap::new(),
            next_serial: 1,
        }
    }

    fn alloc_serial(&mut self) -> i32 {
        let s = self.next_serial;
        self.next_serial += 1;
        s
    }

    fn add_key_to_process(&mut self, pid: u64, serial: i32) {
        self.process_keyrings.entry(pid).or_default().push(serial);
    }

    fn reset_process_keys(&mut self, pid: u64) {
        self.process_keyrings.insert(pid, Vec::new());
    }
}

