const SCHED_OTHER_POLICY: u32 = 0;
const SCHED_BATCH_POLICY: u32 = 3;
const SCHED_IDLE_POLICY: u32 = 5;
const SCHED_DEADLINE_POLICY: u32 = 6;

#[repr(C)]
