    sched_priority: i32,
}

#[derive(Clone, Copy, Debug)]
struct SchedState {
    policy: u32,
    priority: i32,
    nice: i32,
}

impl Default for SchedState {
    fn default() -> Self {
        Self {
            policy: SCHED_OTHER_POLICY,
            priority: 0,
            nice: 0,
        }
    }
}

lazy_static! {
    static ref SCHED_STATES: Mutex<BTreeMap<Pid, SchedState>> = Mutex::new(BTreeMap::new());
}

fn resolve_sched_pid(pid: i32) -> AxResult<Pid> {
    if pid < 0 {
        return Err(AxError::InvalidInput);
    }
    if pid == 0 {
        Ok(current().as_thread().proc_data.proc.pid())
    } else {
        let _ = get_process_data(pid as Pid)?;
        Ok(pid as Pid)
    }
}

fn validate_sched_policy(policy: u32) -> AxResult<()> {
    match policy {
        SCHED_OTHER_POLICY
        | SCHED_FIFO
        | SCHED_RR
        | SCHED_BATCH_POLICY
        | SCHED_IDLE_POLICY
        | SCHED_DEADLINE_POLICY => Ok(()),
        _ => Err(AxError::InvalidInput),
    }
}

fn validate_sched_priority(policy: u32, priority: i32) -> AxResult<()> {
    validate_sched_policy(policy)?;
    if matches!(policy, SCHED_FIFO | SCHED_RR) {
        if (1..=99).contains(&priority) {
            return Ok(());
        }
    } else if priority == 0 {
        return Ok(());
    }
    Err(AxError::InvalidInput)
}

fn sched_state(pid: Pid) -> SchedState {
    *SCHED_STATES
        .lock()
        .get(&pid)
        .unwrap_or(&SchedState::default())
}

fn set_sched_state(pid: Pid, state: SchedState) {
    SCHED_STATES.lock().insert(pid, state);

